    async function switchToOpening(swipeId) {
      // 1. Lấy phần tử thẻ được click
      const clickedCard = event.currentTarget;

      // 2. Vô hiệu hóa thẻ để tránh click lặp lại
      if (clickedCard) {
        clickedCard.style.opacity = '0.6';
        clickedCard.style.pointerEvents = 'none';
      }

      try {
        // 3. Lấy tất cả swipe của tin nhắn đầu tiên (message_id: 0)
        const messages = await getChatMessages('0', { include_swipe: true });

        // 4. Kiểm tra xem swipe mục tiêu có tồn tại không
        if (messages && messages[0].swipes && messages[0].swipes[swipeId]) {
          // 5. Chuyển đổi sang swipe được chỉ định
          await setChatMessage(messages[0].swipes[swipeId], 0, {
            swipe_id: swipeId,
            refresh: 'display_and_render_current',
          });
        } else {
          throw new Error(`Không tìm thấy lời mở đầu ${swipeId}, vui lòng đảm bảo đã thêm tất cả lời mở đầu theo thứ tự.`);
        }
      } catch (error) {
        // 6. Xử lý lỗi: Khôi phục trạng thái thẻ
        console.error('Chuyển đổi lời mở đầu thất bại:', error);
        alert(`Chuyển đổi thất bại: ${error.message}`);
        if (clickedCard) {
          clickedCard.style.opacity = '1';
          clickedCard.style.pointerEvents = 'auto';
        }
      }
    }

