    const tabIcons = mainContainer.querySelectorAll('.op-tab-icon');
    const tabContents = mainContainer.querySelectorAll('.op-tab-content');
    const tabContentWrapper = mainContainer.querySelector('.op-tab-content-wrapper');
    const actionToggleIcons = mainContainer.querySelectorAll('.op-action-toggle-icon');
    const actionOptionGroups = mainContainer.querySelectorAll('.op-action-option-group');
    const actionOptionWrapper = mainContainer.querySelector('.op-action-option-wrapper');

    const themes = ['theme-erotic', 'theme-woodland', 'theme-ocean', 'theme-garden', 'theme-sakura', 'theme-ember'];
    const themeIcons = ['🍇', '☕', '🌊', '🌳', '🌸', '🍊'];

    const stateManager = {
        storage: window.sessionStorage,
        keys: {
            theme: 'opCardThemeIndex',
            avatarState: 'opCardAvatarState',
            activeTab: 'opCardActiveTab',
            contentCollapsed: 'opCardContentCollapsed',
            activeAction: 'opCardActiveAction',
            avatarCollapsed: 'opCardAvatarCollapsed' // New key for avatar collapse state
        },
        save: (key, value) => stateManager.storage.setItem(key, JSON.stringify(value)),
        load: (key, defaultValue) => {
            const value = stateManager.storage.getItem(key);
            return value ? JSON.parse(value) : defaultValue;
        }
    };

    // --- Avatar Collapse/Expand Toggle (New) ---
    let isAvatarCollapsed = stateManager.load(stateManager.keys.avatarCollapsed, false);
    function applyAvatarCollapseState() {
        if (isAvatarCollapsed) {
            avatarSection.classList.add('collapsed');
            avatarToggle.textContent = '😴';
        } else {
            avatarSection.classList.remove('collapsed');
            avatarToggle.textContent = '😍';
        }
    }
    applyAvatarCollapseState();
    avatarToggle.addEventListener('click', () => {
        isAvatarCollapsed = !isAvatarCollapsed;
        applyAvatarCollapseState();
        stateManager.save(stateManager.keys.avatarCollapsed, isAvatarCollapsed);
    });

    // --- 主题切换 ---
    let currentThemeIndex = stateManager.load(stateManager.keys.theme, 0);
    const themeIcon = mainContainer.querySelector('[data-tab="theme"]');
    function applyTheme(index) {
        mainContainer.classList.remove(...themes);
        mainContainer.classList.add(themes[index]);
        if (themeIcon) themeIcon.innerHTML = themeIcons[index];
    }
    applyTheme(currentThemeIndex);
    if (themeIcon) {
        themeIcon.addEventListener('click', () => {
            currentThemeIndex = (currentThemeIndex + 1) % themes.length;
            applyTheme(currentThemeIndex);
            stateManager.save(stateManager.keys.theme, currentThemeIndex);
        });
    }

    // --- 头像切换 ---
    const avatarIcon = mainContainer.querySelector('[data-tab="avatar"]');
    if (avatarIcon && charAvatar) {
        let currentAvatarState = stateManager.load(stateManager.keys.avatarState, 'front');
        function applyAvatarState(state) {
            const frontSrc = charAvatar.getAttribute('data-front-src');
            const backSrc = charAvatar.getAttribute('data-back-src');
            charAvatar.src = (state === 'back' && backSrc && backSrc.includes('.')) ? backSrc : frontSrc;
        }
        applyAvatarState(currentAvatarState);
        avatarIcon.addEventListener('click', () => {
            currentAvatarState = (currentAvatarState === 'front') ? 'back' : 'front';
            applyAvatarState(currentAvatarState);
            stateManager.save(stateManager.keys.avatarState, currentAvatarState);
        });
    }

    // --- 标签页与折叠逻辑 ---
    let activeTabId = stateManager.load(stateManager.keys.activeTab, 'basic');
    let isContentCollapsed = stateManager.load(stateManager.keys.contentCollapsed, false);

    function updateTabViewState() {
        if (isContentCollapsed) {
            tabContentWrapper.classList.add('collapsed');
            tabIcons.forEach(icon => icon.classList.remove('active'));
        } else {
            tabContentWrapper.classList.remove('collapsed');
            tabIcons.forEach(icon => {
                const isFunctional = ['theme', 'avatar'].includes(icon.dataset.tab);
                if (!isFunctional) {
                    icon.classList.toggle('active', icon.dataset.tab === activeTabId);
                }
            });
            tabContents.forEach(content => content.classList.toggle('active', content.id === `tab-${activeTabId}`));
        }
    }

    tabIcons.forEach(icon => {
        const tabId = icon.dataset.tab;
        const isFunctional = ['theme', 'avatar'].includes(tabId);
        if (isFunctional) return;

        icon.addEventListener('click', () => {
            if (activeTabId === tabId && !isContentCollapsed) {
                isContentCollapsed = true;
            } else {
                isContentCollapsed = false;
                activeTabId = tabId;
            }
            stateManager.save(stateManager.keys.activeTab, activeTabId);
            stateManager.save(stateManager.keys.contentCollapsed, isContentCollapsed);
            updateTabViewState();
        });
    });
    updateTabViewState();

    // --- 行动选项逻辑 ---
    let activeActionId = stateManager.load(stateManager.keys.activeAction, null);

    function updateActionViewState() {
        if (activeActionId === null) {
            actionOptionWrapper.classList.add('collapsed');
            actionToggleIcons.forEach(icon => icon.classList.remove('active'));
            actionOptionGroups.forEach(group => group.classList.remove('active'));
        } else {
            actionOptionWrapper.classList.remove('collapsed');
            actionToggleIcons.forEach(icon => icon.classList.toggle('active', icon.dataset.action === activeActionId));
            actionOptionGroups.forEach(group => group.classList.toggle('active', group.id === activeActionId));
        }
    }

    actionToggleIcons.forEach(icon => {
        const actionId = icon.dataset.action;
        icon.addEventListener('click', () => {
            if (activeActionId === actionId) {
                activeActionId = null; // Click again to hide
            } else {
                activeActionId = actionId;
            }
            stateManager.save(stateManager.keys.activeAction, activeActionId);
            updateActionViewState();
        });
    });
    updateActionViewState();

    mainContainer.querySelectorAll('.op-action-option').forEach(option => {
        option.addEventListener('click', function() {
            const textToSet = this.getAttribute('data-action-text');
            if (typeof triggerSlash === 'function') {
                triggerSlash(`/setinput ${textToSet}`);
            } else {
                console.log(`Simulating: /setinput ${textToSet}`);
            }
        });
    });
});
</script>
