<body>

<div class="container" id="main-interface">
    <div class="section">
        <h2>💜 Trái Ác Quỷ M · Bảng Thức Tỉnh 💜</h2>
        <div class="form-group">
            <label>👤 Tên</label>
            <input type="text" value="{{user}}" readonly>
        </div>
        <div class="form-group">
            <label>🍎 Năng lực</label>
