</div>

<script>
    function toggleAccordion(header) {
        const content = header.nextElementSibling;
        const isActive = content.classList.contains('active');
        document.querySelectorAll('.accordion-content').forEach(c => c.classList.remove('active'));
        if (!isActive) content.classList.add('active');
    }

    // Hiệu ứng: Cánh hoa rơi
    const container = document.getElementById('main-interface');
    container.addEventListener('mousemove', (e) => {
        if (Math.random() > 0.3) return;
        const item = document.createElement('div');
        item.classList.add('falling-item');
        item.innerText = '🌸';
        const offsetX = (Math.random() - 0.5) * 50;
        const startX = e.clientX - container.getBoundingClientRect().left + offsetX;
        const startY = e.clientY - container.getBoundingClientRect().top;
        item.style.left = startX + 'px';
        item.style.top = startY + 'px';
        const size = Math.random() * 10 + 10;
        item.style.fontSize = size + 'px';
        container.appendChild(item);
        setTimeout(() => item.remove(), 1000);
    });

    function sendScenario(type) {
        const bgInput = document.getElementById('bg-input').value.trim() || "Ngoại hình chính thái (shota) thanh tú mặc định.";
        const fetishInput = document.getElementById('fetish-input').value.trim() || "Tùy cơ ứng biến.";
        const modeInput = document.getElementById('mode-input').value;

        let scenarioConfig = {};

        if (type === 'A') {
            scenarioConfig = {
                title: "Miss All Sunday",
                context: "Thời điểm: Lần đầu gặp gỡ (Thời kỳ tàu Merry). Địa điểm: Boong tàu Merry. Nhân vật: Robin (Nico Robin). Thân phận: Phó giám đốc Baroque Works (Robin) vs Thuyền trưởng băng Mũ Rơm (Người chơi). Sự kiện: Người phụ nữ bí ẩn đột nhiên xuất hiện trên tàu, bánh răng định mệnh bắt đầu xoay chuyển.",
                relation: "Từ người lạ bí ẩn chuyển biến thành mối quan hệ được định nghĩa bởi [Trạng thái khởi đầu]"
            };
        } else if (type === 'B') {
            scenarioConfig = {
                title: "Khảo Cổ Học Đêm Khuya",
                context: "Thời điểm: Đang lênh đênh trên biển. Địa điểm: Phòng thuyền trưởng. Nhân vật: Robin (Nico Robin). Thân phận: Thuyền trưởng (Người chơi) vs Nhà khảo cổ học (Robin). Sự kiện: Robin ghé thăm lúc đêm khuya, tiến hành giao lưu sâu sắc về tri thức và thể xác trong không gian kín.",
                relation: "Bề ngoài là đồng đội -> Bên trong là quan hệ thống trị dựa trên [Trạng thái khởi đầu]"
            };
        } else if (type === 'C') {
            scenarioConfig = {
                title: "Quán Cafe Lộ Thiên",
                context: "Thời điểm: Đang trong chuyến phiêu lưu. Địa điểm: Quán cafe lộ thiên. Nhân vật: Robin (Nico Robin). Sự kiện: Lợi dụng [Màn Che Danh Dự] và [Trái Hana Hana] để thực hiện tương tác bí mật ngay tại nơi công cộng.",
                relation: "Mối quan hệ bí mật dựa trên [Trạng thái khởi đầu]"
            };
        }

        const promptText = `
<onepieceStart>
[Hệ thống chỉ lệnh: Khởi tạo tuyến truyện Trái M - Nhân vật: Robin]
<setup>
Người chơi: {{user}}
Nhân vật: Nico Robin
Năng lực: Trái M (Dạng can thiệp khái niệm)
Thiết lập ngoại hình: ${bgInput}
Sở thích play: ${fetishInput}
Trạng thái của Robin: ${modeInput}
Kịch bản: ${scenarioConfig.title}
Tình huống: ${scenarioConfig.context}
</setup>

Cốt lõi thực thi:
1. **Định nghĩa nghiêm ngặt trạng thái của Robin**:
    - Nếu là [抖S女王] (Nữ Vương S): Cô ấy là nhà khảo cổ học bụng đen (haramaguro) và đầy ác thú, coi người chơi là "mẫu vật lịch sử" thú vị hoặc "đồ chơi", thích dùng lời nói trêu chọc và kỹ thuật khóa khớp (Trái Hana Hana) để thống trị.
    - Nếu là [温柔伴侣] (Bạn Đời Dịu Dàng): Cô ấy là người chị trưởng thành và tri thức, coi người chơi là em trai/người yêu cần được che chở, dùng sự bao dung của người trưởng thành để dẫn dắt dục vọng của người chơi.
    - Nếu là [专属母猪] (Heo Nái Riêng): Cô ấy là "Đứa con của quỷ" khao khát được sống, từ bỏ lòng tự trọng để tìm kiếm sự che chở, tự nguyện trở thành công cụ tình dục của người chơi.

2. Triển khai kịch bản:
    - Kết hợp <Thiết lập ngoại hình> và <Sở thích play>, miêu tả một đoạn mở đầu mang phong thái trưởng thành và đầy sức căng sắc dục.
    - Thực hiện nghiêm ngặt thiết lập thân phận trong <Tình huống>, nhưng quan hệ quyền lực do <Trạng thái của Robin> quyết định.
    - Tập trung miêu tả hiệu quả của 【Trái M】 (như sự che đậy của Màn Che Danh Dự, ảnh hưởng của Cộng Hưởng Dục Vọng) và ứng dụng của 【Trái Hana Hana】 trong tương tác tình dục.
    - Nếu ở chế độ [Heo Nái Riêng], hãy thể hiện sự xâm lấn của năng lực trái ác quỷ đối với sự lý trí và vẻ ngoài bình tĩnh của Robin.

3. Tạo thanh trạng thái ở cuối:
    - Vui lòng dựa trên định nghĩa của World Info để tạo thanh trạng thái ở cuối, và bắt buộc dùng thẻ <OPStatus> và </OPStatus> để bao bọc nó.
</onepieceStart>
`;

        if (typeof triggerSlash === 'function') {
            triggerSlash(`/send ${promptText} | /trigger`);
        } else {
            console.log("Mô phỏng gửi đi:", promptText);
            alert("💜 Lệnh đã được tạo, vui lòng chạy trong môi trường ST!");
        }

        container.style.transition = 'opacity 0.5s';
        container.style.opacity = '0';
        setTimeout(() => {
            container.style.display = 'none';
        }, 500);
    }
</script>

</body>
</html>
