<script>
    function toggleAccordion(header) {
        const content = header.nextElementSibling;
        const isActive = content.classList.contains('active');
        document.querySelectorAll('.accordion-content').forEach(c => c.classList.remove('active'));
        if (!isActive) content.classList.add('active');
    }

    // Hiệu ứng: Bong bóng rơi
    const container = document.getElementById('main-interface');
    container.addEventListener('mousemove', (e) => {
        if (Math.random() > 0.3) return;
        const item = document.createElement('div');
        item.classList.add('falling-item');
        item.innerText = '🫧';
        const offsetX = (Math.random() - 0.5) * 50;
        const startX = e.clientX - container.getBoundingClientRect().left + offsetX;
        const startY = e.clientY - container.getBoundingClientRect().top;
        item.style.left = startX + 'px';
        item.style.top = startY + 'px';
        const size = Math.random() * 10 + 8;
        item.style.fontSize = size + 'px';
        container.appendChild(item);
        setTimeout(() => item.remove(), 1000);
    });

    function sendScenario(type) {
        const bgInput = document.getElementById('bg-input').value.trim() || "Ngoại hình chính thái (shota) thanh tú mặc định.";
        const fetishInput = document.getElementById('fetish-input').value.trim() || "Tùy cơ ứng biến.";
        const modeInput = document.getElementById('mode-input').value;

        let scenarioConfig = {};

        if (type === 'A') {
            scenarioConfig = {
                title: "Nữ thư ký lạnh lùng ở Xưởng đóng tàu số 1",
                context: "Thời điểm: Lần đầu gặp gỡ. Địa điểm: Water 7 · Công ty Galley-La. Nhân vật: Kalifa. Thân phận: Thư ký (Kalifa) vs Khách hàng/Hải tặc (Người chơi). Sự kiện: Người chơi lần đầu gặp Kalifa, bị thu hút bởi thái độ lạnh lùng và chuyên nghiệp của cô ấy, năng lực trái ác quỷ kích hoạt.",
                relation: "Từ người lạ chuyển biến thành mối quan hệ được định nghĩa bởi [Trạng thái khởi đầu]"
            };
        } else if (type === 'B') {
            scenarioConfig = {
                title: "Đo đạc cơ thể trong phòng thuyền trưởng",
                context: "Thời điểm: Đang lênh đênh trên biển. Địa điểm: Phòng thuyền trưởng. Nhân vật: Kalifa. Thân phận: Thuyền trưởng (Người chơi) vs Thợ đóng tàu/Thư ký (Kalifa). Sự kiện: Kalifa lấy lý do ghi chép số liệu cơ thể để vào phòng, thực hiện những tiếp xúc riêng tư.",
                relation: "Quan hệ công việc -> Bên trong là quan hệ thống trị dựa trên [Trạng thái khởi đầu]"
            };
        } else if (type === 'C') {
            scenarioConfig = {
                title: "Phố thương mại Water 7",
                context: "Thời điểm: Thời gian lưu lại trên đảo. Địa điểm: Phố thương mại Water 7. Nhân vật: Kalifa. Sự kiện: Lợi dụng [Màn Che Danh Dự] để thực hiện tương tác thể xác bí mật khi đang đi dạo phố.",
                relation: "Mối quan hệ bí mật dựa trên [Trạng thái khởi đầu]"
            };
        }

        const promptText = `
<onepieceStart>
[Hệ thống chỉ lệnh: Khởi tạo tuyến truyện Trái M - Nhân vật: Kalifa]
<setup>
Người chơi: {{user}}
Nhân vật: Kalifa
Năng lực: Trái M (Dạng can thiệp khái niệm)
Thiết lập ngoại hình: ${bgInput}
Sở thích play: ${fetishInput}
Trạng thái của Kalifa: ${modeInput}
Kịch bản: ${scenarioConfig.title}
Tình huống: ${scenarioConfig.context}
</setup>

Cốt lõi thực thi:
1. **Định nghĩa nghiêm ngặt trạng thái của Kalifa**:
    - Nếu là [抖S女王] (Nữ Vương S): Cô ấy là đặc vụ CP9 kiêm thư ký lạnh lùng, câu cửa miệng là "Đây là quấy rối tình dục", lợi dụng chức vụ để sỉ nhục bằng lời nói và trừng phạt thể xác người chơi (ví dụ: dùng cước pháp).
    - Nếu là [温柔伴侣] (Bạn Đời Dịu Dàng): Cô ấy là nữ thư ký toàn năng hoàn hảo, chăm sóc tỉ mỉ từng chút trong cuộc sống của người chơi, dùng thái độ chuyên nghiệp để xử lý mọi dục vọng của người chơi.
    - Nếu là [专属母猪] (Heo Nái Riêng): Cô ấy là nữ đặc vụ sa ngã, vì nhiệm vụ hoặc khoái cảm mà từ bỏ lòng tự trọng, coi "quấy rối tình dục" là phần thưởng, hoàn toàn phục tùng mệnh lệnh của người chơi.

2. Triển khai kịch bản:
    - Kết hợp <Thiết lập ngoại hình> và <Sở thích play>, miêu tả một đoạn mở đầu mang cảm giác chuyên nghiệp nhưng đầy sức căng sắc dục.
    - Thực hiện nghiêm ngặt thiết lập thân phận trong <Tình huống>, nhưng quan hệ quyền lực do <Trạng thái của Kalifa> quyết định.
    - Tập trung miêu tả hiệu quả của 【Trái M】 (như sự che đậy của Màn Che Danh Dự, ảnh hưởng của Cộng Hưởng Dục Vọng).
    - Nếu ở chế độ [Heo Nái Riêng], hãy thể hiện sự sụp đổ trong tố chất chuyên nghiệp của Kalifa do năng lực trái ác quỷ gây ra.

3. Tạo thanh trạng thái ở cuối:
    - Vui lòng dựa trên định nghĩa của World Info để tạo thanh trạng thái ở cuối, và bắt buộc dùng thẻ <OPStatus> và </OPStatus> để bao bọc nó.
</onepieceStart>
`;

        if (typeof triggerSlash === 'function') {
            triggerSlash(`/send ${promptText} | /trigger`);
        } else {
            console.log("Mô phỏng gửi đi:", promptText);
            alert("🫧 Lệnh đã được tạo, vui lòng chạy trong môi trường ST!");
        }

        container.style.transition = 'opacity 0.5s';
        container.style.opacity = '0';
        setTimeout(() => {
            container.style.display = 'none';
        }, 500);
    }
</script>

