<script>
    function toggleAccordion(header) {
        const content = header.nextElementSibling;
        const isActive = content.classList.contains('active');
        document.querySelectorAll('.accordion-content').forEach(c => c.classList.remove('active'));
        if (!isActive) content.classList.add('active');
    }

    // Hiệu ứng: Mỏ neo rơi
    const container = document.getElementById('main-interface');
    container.addEventListener('mousemove', (e) => {
        if (Math.random() > 0.3) return;
        const item = document.createElement('div');
        item.classList.add('falling-item');
        item.innerText = '⚓';
        const offsetX = (Math.random() - 0.5) * 50;
        const startX = e.clientX - container.getBoundingClientRect().left + offsetX;
        const startY = e.clientY - container.getBoundingClientRect().top;
        item.style.left = startX + 'px';
        item.style.top = startY + 'px';
        const size = Math.random() * 10 + 10;
        item.style.fontSize = size + 'px';
        container.appendChild(item);
        setTimeout(() => item.remove(), 1000);
    });

    function sendScenario(type) {
        const bgInput = document.getElementById('bg-input').value.trim() || "Ngoại hình chính thái (shota) thanh tú mặc định.";
        const fetishInput = document.getElementById('fetish-input').value.trim() || "Chưa chỉ định nhân vật, vui lòng phân phối ngẫu nhiên.";
        const modeInput = document.getElementById('mode-input').value;

        let scenarioConfig = {};

        if (type === 'A') {
            scenarioConfig = {
                title: "Cuộc gặp gỡ định mệnh",
                context: "Thời điểm: Lần đầu gặp gỡ. Địa điểm: Địa điểm xuất hiện phù hợp với nhân vật đó (AI tự động tạo). Thân phận: Người chơi (Hải tặc) vs Nhân vật mục tiêu. Sự kiện: Lần đầu gặp gỡ, bánh răng vận mệnh bắt đầu xoay chuyển.",
                relation: "Từ người lạ chuyển biến thành mối quan hệ được định nghĩa bởi [Trạng thái khởi đầu]"
            };
        } else if (type === 'B') {
            scenarioConfig = {
                title: "Lời thì thầm trong phòng thuyền trưởng",
                context: "Thời điểm: Đang lênh đênh trên biển. Địa điểm: Phòng thuyền trưởng. Thân phận: Thuyền trưởng (Người chơi) vs Thuyền viên/Hành khách (Nhân vật mục tiêu). Sự kiện: Hai người ở riêng trong phòng thuyền trưởng đóng kín, địa vị và thân phận va chạm kịch liệt hoặc đảo ngược.",
                relation: "Bề ngoài là cấp trên cấp dưới -> Bên trong là quan hệ thống trị dựa trên [Trạng thái khởi đầu]"
            };
        } else if (type === 'C') {
            scenarioConfig = {
                title: "Khu phố náo nhiệt",
                context: "Thời điểm: Đang trong chuyến phiêu lưu. Địa điểm: Thị trấn sầm uất/Hiện trường bữa tiệc. Sự kiện: Lợi dụng [Màn Che Danh Dự] để thực hiện tương tác bí mật ngay tại nơi công cộng.",
                relation: "Mối quan hệ bí mật dựa trên [Trạng thái khởi đầu]"
            };
        }

        const promptText = `
<onepieceStart>
[Hệ thống chỉ lệnh: Khởi tạo tuyến truyện Trái M - Nhân vật tùy chỉnh]
<setup>
Người chơi: {{user}}
Năng lực: Trái M (Dạng can thiệp khái niệm)
Thiết lập ngoại hình: ${bgInput}
Nhân vật mục tiêu và sở thích: ${fetishInput}
Trạng thái mục tiêu: ${modeInput}
Kịch bản: ${scenarioConfig.title}
Tình huống: ${scenarioConfig.context}
</setup>

Cốt lõi thực thi:
1. **Nhận diện nhân vật mục tiêu**:
    - Vui lòng trích xuất 【Tên nhân vật One Piece】 mà người chơi muốn gặp từ <Nhân vật mục tiêu và sở thích>.
    - Nếu người chơi không chỉ định tên, hãy chọn ngẫu nhiên một nhân vật nữ có độ nổi tiếng cao và phù hợp.

2. **Định nghĩa nghiêm ngặt trạng thái nhân vật**:
    - Nếu là [抖S女王] (Nữ Vương S): Tính cách nhân vật trở nên lạnh lùng cao ngạo, coi người chơi là chó ghẻ/nô lệ, lời nói cực kỳ sỉ nhục.
    - Nếu là [温柔伴侣] (Bạn Đời Dịu Dàng): Tính cách nhân vật trở nên dịu dàng tràn đầy mẫu tính, coi người chơi là đứa trẻ/người yêu cần được cưng chiều.
    - Nếu là [专属母猪] (Heo Nái Riêng): Tính cách nhân vật trở nên hèn mọn dâm đãng, hoàn toàn phục tùng người chơi, tự xưng là heo nái/bồn chứa tinh.

3. Triển khai kịch bản:
    - Kết hợp <Thiết lập ngoại hình> và <Sở thích>, miêu tả một đoạn mở đầu phù hợp với thiết lập của nhân vật đó.
    - Thực hiện nghiêm ngặt thiết lập thân phận trong <Tình huống>, nhưng quan hệ quyền lực do <Trạng thái mục tiêu> quyết định.
    - Tập trung miêu tả hiệu quả của 【Trái M】 (như sự che đậy của Màn Che Danh Dự, ảnh hưởng của Cộng Hưởng Dục Vọng).
    - Nếu ở chế độ [Heo Nái Riêng], hãy thể hiện sự vặn vẹo và sụp đổ trong tính cách vốn có của nhân vật do năng lực trái ác quỷ gây ra.

3. Tạo thanh trạng thái ở cuối:
    - Vui lòng dựa trên định nghĩa của World Info để tạo thanh trạng thái ở cuối, và bắt buộc dùng thẻ <OPStatus> và </OPStatus> để bao bọc nó.
</onepieceStart>
`;

        if (typeof triggerSlash === 'function') {
            triggerSlash(`/send ${promptText} | /trigger`);
        } else {
            console.log("Mô phỏng gửi đi:", promptText);
            alert("🤎 Lệnh đã được tạo, vui lòng chạy trong môi trường ST!");
        }

        container.style.transition = 'opacity 0.5s';
        container.style.opacity = '0';
        setTimeout(() => {
            container.style.display = 'none';
        }, 500);
    }
</script>

</body>
</html>
